function toggleView(mode) {
    document.body.setAttribute('data-view', mode);
    window.scrollTo(0, 0);
}

function draw() {
    const raw = document.getElementById('json-pen').value;
    const stack = document.getElementById('document-stack');

    try {
        const pages = JSON.parse(raw);
        stack.innerHTML = '';

        pages.forEach(pageData => {
            const pageDiv = document.createElement('div');
            pageDiv.className = `page-surface type-${pageData.layout || 'standard'}`;

            // Add Magnify icon to top corner of every page
            const mag = document.createElement('button');
            mag.className = 'magnify-btn';
            mag.innerHTML = '🔍';
            mag.onclick = () => toggleView('reader');
            pageDiv.appendChild(mag);

            pageData.content.forEach(item => {
                const el = document.createElement('div');

                if (item.type === 'paragraph') {
                    el.className = 'p-block';
                    el.innerHTML = item.body; 
                } 
                else if (item.type === 'header') {
                    el.className = 'h-block';
                    el.innerHTML = item.body;
                }
                else if (item.type === 'toc-item') {
                    el.className = 'toc-row';
                    el.innerHTML = `<span class="toc-label">${item.label}</span><span class="toc-dots"></span><span class="toc-page">${item.page}</span>`;
                }
                else if (item.type === 'reflection') {
                    el.className = 'reflection-box';
                    el.innerHTML = `<strong>Reflection:</strong><br>${item.body}`;
                }
                else if (item.type === 'footer') {
                    el.className = 'footer';
                    el.innerText = item.val;
                }

                pageDiv.appendChild(el);
            });

            stack.appendChild(pageDiv);
        });

    } catch (err) {
        alert("Data Structure Error: " + err);
    }
}

